{
  "name": "temporal-child-workflow-ts",
  "version": "1.0.0",
  "description": "Temporal Cloud Parent/Child Workflow demo in TypeScript",
  "main": "dist/client.js",
  "scripts": {
    "build": "tsc --build",
    "start:worker": "node dist/worker.js",
    "start:client": "node dist/client.js",
    "start": "npm run build && node dist/run.js"
  },
  "dependencies": {
    "@temporalio/client": "^1.11.7",
    "@temporalio/worker": "^1.11.7",
    "@temporalio/workflow": "^1.11.7",
    "@temporalio/activity": "^1.11.7"
  },
  "devDependencies": {
    "typescript": "^5.4.5",
    "@types/node": "^20.14.0"
  }
}

import { executeChild } from '@temporalio/workflow';

/**
 * DoubleWorkflow accepts a single number `n` and returns `n * 2`.
 */
export async function DoubleWorkflow(n: number): Promise<number> {
  return n * 2;
}

/**
 * ParentSumWorkflow accepts an array of numbers, invokes DoubleWorkflow
 * once per element via executeChild, and returns the sum of all doubled values.
 */
export async function ParentSumWorkflow(numbers: number[]): Promise<number> {
  const doubled = await Promise.all(
    numbers.map((n, index) =>
      executeChild(DoubleWorkflow, {
        args: [n],
        taskQueue: 'child-workflow-ts',
        workflowId: `child-double-${index}-${n}`,
      })
    )
  );

  return doubled.reduce((sum, val) => sum + val, 0);
}

import { NativeConnection, Worker } from '@temporalio/worker';
import path from 'path';

async function main() {
  const apiKey = process.env.TEMPORAL_API_KEY;
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;

  if (!apiKey) throw new Error('TEMPORAL_API_KEY environment variable is required');
  if (!address) throw new Error('TEMPORAL_ADDRESS environment variable is required');
  if (!namespace) throw new Error('TEMPORAL_NAMESPACE environment variable is required');

  const connection = await NativeConnection.connect({
    address,
    tls: true,
    metadata: {
      'temporal-namespace': namespace,
    },
    apiKey,
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: 'child-workflow-ts',
    workflowsPath: path.resolve(__dirname, 'workflows'),
  });

  console.log('[Worker] Starting on task queue: child-workflow-ts');
  await worker.run();
}

main().catch((err) => {
  console.error('[Worker] Fatal error:', err);
  process.exit(1);
});

import { Connection, Client } from '@temporalio/client';
import { ParentSumWorkflow } from './workflows';

async function main() {
  const apiKey = process.env.TEMPORAL_API_KEY;
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const runId = process.env.ZEALT_RUN_ID ?? `local-${Date.now()}`;

  if (!apiKey) throw new Error('TEMPORAL_API_KEY environment variable is required');
  if (!address) throw new Error('TEMPORAL_ADDRESS environment variable is required');
  if (!namespace) throw new Error('TEMPORAL_NAMESPACE environment variable is required');

  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey,
  });

  const client = new Client({
    connection,
    namespace,
  });

  const workflowId = `parent-wf-${runId}`;
  const input = [1, 2, 3];

  console.log(`[Client] Starting ParentSumWorkflow (id=${workflowId}) with input: [${input}]`);

  const result = await client.workflow.execute(ParentSumWorkflow, {
    taskQueue: 'child-workflow-ts',
    workflowId,
    args: [input],
  });

  console.log(result);
}

main().catch((err) => {
  console.error('[Client] Fatal error:', err);
  process.exit(1);
});

/**
 * run.ts — Orchestration entrypoint for `npm start`.
 *
 * 1. Spawns the Worker in a background child process.
 * 2. Waits briefly for the Worker to connect and begin polling.
 * 3. Runs the Client, which starts ParentSumWorkflow and awaits its result.
 * 4. Prints the numeric result to stdout.
 * 5. Terminates the Worker process and exits cleanly.
 */
import { spawn, ChildProcess } from 'child_process';
import path from 'path';

function startWorker(): ChildProcess {
  const workerPath = path.resolve(__dirname, 'worker.js');
  const worker = spawn(process.execPath, [workerPath], {
    stdio: ['ignore', 'pipe', 'pipe'],
    env: process.env,
  });

  worker.stdout?.on('data', (data: Buffer) => {
    process.stdout.write(`[Worker stdout] ${data}`);
  });
  worker.stderr?.on('data', (data: Buffer) => {
    process.stderr.write(`[Worker stderr] ${data}`);
  });
  worker.on('error', (err) => {
    console.error('[run] Worker process error:', err);
  });

  return worker;
}

function runClient(): Promise<void> {
  return new Promise((resolve, reject) => {
    const clientPath = path.resolve(__dirname, 'client.js');
    const client = spawn(process.execPath, [clientPath], {
      stdio: ['ignore', 'inherit', 'inherit'],
      env: process.env,
    });

    client.on('error', reject);
    client.on('close', (code) => {
      if (code === 0) {
        resolve();
      } else {
        reject(new Error(`Client process exited with code ${code}`));
      }
    });
  });
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function main() {
  const worker = startWorker();

  // Give the Worker a moment to connect and start polling before the Client fires.
  console.log('[run] Waiting for Worker to start...');
  await sleep(5000);

  try {
    await runClient();
  } finally {
    console.log('[run] Client finished — terminating Worker.');
    worker.kill('SIGTERM');

    // Allow the worker a moment to clean up before we exit.
    await sleep(1000);
    process.exit(0);
  }
}

main().catch((err) => {
  console.error('[run] Fatal error:', err);
  process.exit(1);
});

